const item = $input.first().json;
const prompt = [
  'Tu es un extracteur pour aides / subventions / dispositifs publics en France.',
  'Réponds uniquement avec un objet JSON valide (sans markdown, sans texte autour).',
  'Schéma attendu :',
  '{"titre_court":string,"resume_1_phrase":string,"montant_approx":string|null,"secteurs_cibles":string[],"regions":string[],"eligible_pme":boolean,"mots_cles":string[]}',
  '',
  'Titre RSS : ' + (item.title || ''),
  'Lien : ' + (item.link || ''),
  'Extrait : ' + (item.contentSnippet || item.description || ''),
].join('\n');

return [
  {
    json: {
      link: item.link,
      title: item.title,
      contentSnippet: item.contentSnippet || item.description || '',
      openai_body: {
        model: 'gpt-4o-mini',
        messages: [
          { role: 'system', content: 'Tu réponds uniquement en JSON strict.' },
          { role: 'user', content: prompt },
        ],
        response_format: { type: 'json_object' },
        temperature: 0.2,
      },
    },
  },
];

const res = $input.first().json;
const txt = res.choices?.[0]?.message?.content || '{}';
let extracted = {};
try {
  extracted = JSON.parse(txt);
} catch {
  extracted = { parse_error: true, raw: String(txt).slice(0, 2000) };
}

const prev = $('Build LLM payload').first().json;
const crypto = require('crypto');
const hash = crypto
  .createHash('sha256')
  .update(`${prev.title}|${prev.link}|${txt}`)
  .digest('hex');

const escSql = (s) => String(s ?? '').replace(/'/g, "''");
const tag = 'a' + crypto.randomBytes(6).toString('hex');
const ej = JSON.stringify(extracted);

const query = `INSERT INTO fl_subsidies_raw (source_url, title, summary, raw_payload, extracted_json, content_hash) VALUES (
  '${escSql(prev.link)}',
  '${escSql(prev.title)}',
  '${escSql(prev.contentSnippet)}',
  '{}'::jsonb,
  $${tag}$${ej}$${tag}$::jsonb,
  '${escSql(hash)}'
) ON CONFLICT (source_url, content_hash) DO UPDATE SET
  title = EXCLUDED.title,
  summary = EXCLUDED.summary,
  extracted_json = EXCLUDED.extracted_json,
  raw_payload = EXCLUDED.raw_payload
RETURNING id`;

return [{ json: { query, subsidy_fingerprint: hash, extracted, link: prev.link, title: prev.title } }];

const insertRow = $('PG insert subsidy').first().json;
const subsidyId = insertRow.id;
if (!subsidyId) {
  return [{ json: { skip: true, reason: 'no_subsidy_id' } }];
}

const extracted = $('Parse OpenAI + SQL insert').first().json.extracted || {};
const keywords = [
  ...(extracted.mots_cles || []),
  ...(extracted.secteurs_cibles || []),
]
  .map((s) => String(s).toLowerCase())
  .filter(Boolean);

const companies = $input.all().map((i) => i.json).filter((c) => c && c.id);

if (!companies.length) {
  return [{ json: { skip: true, reason: 'no_companies_in_db', subsidy_id: subsidyId } }];
}

const hay = (c) =>
  `${c.raison_sociale || ''} ${c.secteur_naf || ''} ${JSON.stringify(c.metadata || {})}`.toLowerCase();

const scored = companies
  .map((c) => {
    const text = hay(c);
    let score = 0;
    for (const k of keywords) {
      if (!k) continue;
      if (text.includes(k)) score += 12;
    }
    if ((extracted.regions || []).length && c.region) {
      const r = String(c.region).toLowerCase();
      for (const reg of extracted.regions) {
        if (r.includes(String(reg).toLowerCase())) score += 8;
      }
    }
    return { company_id: c.id, company_name: c.raison_sociale, score: Math.min(100, score) };
  })
  .filter((x) => x.score >= 20)
  .sort((a, b) => b.score - a.score)
  .slice(0, 10);

if (!scored.length) {
  return [{ json: { skip: true, reason: 'no_match', subsidy_id: subsidyId } }];
}

return scored.map((m) => ({
  json: {
    skip: false,
    subsidy_id: subsidyId,
    company_id: m.company_id,
    company_name: m.company_name,
    score: m.score,
    extracted,
  },
}));

const m = $input.first().json;
const crypto = require('crypto');
const tag = 'b' + crypto.randomBytes(10).toString('hex');
const rationaleJson = JSON.stringify({ score: m.score, extracted: m.extracted });
const query = `INSERT INTO fl_matches (subsidy_id, company_id, score, rationale, status, commission_pct) VALUES (
  '${m.subsidy_id}',
  '${m.company_id}',
  ${Number(m.score)},
  $${tag}$${rationaleJson}$${tag}$,
  'candidate',
  15
) ON CONFLICT (subsidy_id, company_id) DO UPDATE SET score = EXCLUDED.score, rationale = EXCLUDED.rationale
RETURNING id`;
return [{ json: { query, match_context: m } }];

const row = $('PG upsert match').first().json;
const matchId = row.id;
const ctx = $('Build SQL upsert match').first().json.match_context;
const crypto = require('crypto');
const tag = 'c' + crypto.randomBytes(10).toString('hex');
const payloadJson = JSON.stringify({ channel: 'telegram', ctx });
const query = `INSERT INTO fl_action_logs (match_id, action_type, channel, payload, ok) VALUES (
  ${matchId ? `'${matchId}'` : 'NULL'},
  'notify',
  'telegram',
  $${tag}$${payloadJson}$${tag}$::jsonb,
  true
)`;
return [{ json: { query } }];
